-- ══════════════════════════════════════════
-- STEP 1: Drop old tables
-- ══════════════════════════════════════════
DROP TABLE IF EXISTS applications CASCADE;
DROP TABLE IF EXISTS schemes CASCADE;

-- ══════════════════════════════════════════
-- STEP 2: Create schemes table
-- ══════════════════════════════════════════
CREATE TABLE schemes (
  id                         SERIAL PRIMARY KEY,
  "श्रेणी"                   TEXT,
  "योजना का नाम"             TEXT,
  "योजना का विवरण"           TEXT,
  "पात्रता का विवरण"         TEXT,
  "आवश्यक दस्तावेज़"         TEXT,
  "मिलने वाले लाभ का विवरण"  TEXT,
  "कार्यदायी विभाग"           TEXT
);

ALTER TABLE schemes ENABLE ROW LEVEL SECURITY;
CREATE POLICY "public_read_schemes" ON schemes FOR SELECT TO anon USING (true);

-- ══════════════════════════════════════════
-- STEP 3: Create applications table
-- ══════════════════════════════════════════
CREATE TABLE applications (
  id                   SERIAL PRIMARY KEY,
  "नाम"               TEXT,
  "पिता का नाम"        TEXT,
  "गाँव"              TEXT,
  "ब्लॉक"             TEXT,
  "मोबाइल नंबर"       TEXT,
  "आधार नंबर"         TEXT,
  selected_scheme_id   INTEGER REFERENCES schemes(id),
  created_at           TIMESTAMPTZ DEFAULT NOW()
);

ALTER TABLE applications ENABLE ROW LEVEL SECURITY;
CREATE POLICY "public_insert_applications" ON applications FOR INSERT TO anon WITH CHECK (true);

-- ══════════════════════════════════════════
-- STEP 4: Insert scheme data
-- ══════════════════════════════════════════
INSERT INTO schemes ("श्रेणी","योजना का नाम","योजना का विवरण","पात्रता का विवरण","आवश्यक दस्तावेज़","मिलने वाले लाभ का विवरण","कार्यदायी विभाग") VALUES
('किसान','प्रधानमंत्री आवास ग्रामीण','ग्रामीण क्षेत्रों में ऐसे परिवार जिनके पास रहने को घर नहीं है या कच्चा घर है, छप्पर, मढ़ई इत्यादि है उन्हें इस योजना के तहत सर्वे के आधार पर पात्रता सूची में सम्मिलित करते हुए वरियता  क्रम अनुसार आवास प्रदान किया जाता है','घर नहीं है या कच्चा घर है, छप्पर, मढ़ई इत्यादि, मासिक आय 15,000/ प्रति माह से कम हो, २५ वर्ग मीटर ज़मीन उपलब्ध हो तथा आवास प्लस सर्वे २०२४ में नाम होना आवश्यक है','ज़मीन का विवरण ( घर का न्यूनतम आकार 25 वर्ग मीटर होना ), आधार कार्ड, बैंक पासबुक, मनरेगा जॉब कार्ड , मोबाइल नम्बर','प्रथम किश्त - 40,000/ , द्वितीय किश्त - 7०,०००/ , तीसरी किश्त - 1०,०००/ , मनरेगा योजना अंतर्गत  90 मानव दिवस की मजदूरी , सम्पूर्ण स्वच्छता अभियान के अंतर्गत शौचालय निर्माण १२०००/ की धनराशि दी जाती है','ग्राम्य विकास'),
('किसान','मुख्यमंत्री आवास ग्रामीण','प्राकृतिक आपदा से पीड़ित परिवार, दिव्यांगजन, कुष्ठ रोगी, निराश्रित विधवा (उम्र ५० वर्ष के कम), कोल, नट  , मुसहर, धैकार, सपेरा / सपेरिया इत्यादि','घर नहीं है या कच्चा घर है, छप्पर, मढ़ई इत्यादि, मासिक आय 15,000/ प्रति माह से कम हो, २५ वर्ग मीटर ज़मीन उपलब्ध हो तथा आवास प्लस सर्वे २०२४ में नाम होना आवश्यक है','ज़मीन का विवरण ( घर का न्यूनतम आकार 25 वर्ग मीटर होना ), जाति प्रमाण पत्र,
आय प्रमाण पत्र आधार कार्ड, बैंक पासबुक, मनरेगा जॉब कार्ड , मोबाइल नम्बर','प्रथम किश्त - 40,000/ , द्वितीय किश्त - 7०,०००/ , तीसरी किश्त - 1०,०००/ , मनरेगा योजना अंतर्गत  90 मानव दिवस की मजदूरी , सम्पूर्ण स्वच्छता अभियान के अंतर्गत शौचालय निर्माण १२०००/ की धनराशि दी जाती है','ग्राम्य विकास'),
('वृद्धजन','वृद्धावस्था पेंशन','वृद्धजन जिनकी आयु ६० वर्ष से उपर हो उन्हें १,०००/ प्रति माह के हिसाब से तिमाही ३,०००/ वर्ष में ४ बार दिया जाता है।','आयु - ६० वर्ष से अधिक हो, वार्षिक आय - ४६,०८० / से कम हो।','आधार कार्ड, परिवार रजिस्टर की नकल, आय प्रमाण पत्र, बैंक खाता','१,०००/ प्रति माह के हिसाब से तिमाही ३,०००/ वर्ष में ४ बार दिया जाता है।','समाज कल्याण विभाग'),
('वृद्धजन','पारिवारिक लाभ','परिवार के कमाऊ सदस्य की आकस्मिक मृत्यु हो जाने पर परिवार को ३०,००० रू एक मुश्त अनुदान दिया जाता है।','मृतक की उम्र १८ वर्ष से अधिक, ६० वर्ष से कम होनी चाइए।','आधार कार्ड, परिवार रजिस्टर की नकल, मृत्यु प्रमाण पत्र, आय प्रमाण पत्र, बैंक खाता','परिवार के कमाऊ सदस्य की आकस्मिक मृत्यु हो जाने पर परिवार को ३०,००० रू एक मुश्त अनुदान दिया जाता है।','समाज कल्याण विभाग'),
('वृद्धजन','मुख्यमंत्री सामूहिक विवाह','ऐसे परिवार जिनकी वार्षिक आय - ३,००,००० रू से कम हो उन परिवार के बच्चियों की इस योजना के तहत सम्मिलित शादी होने पर ६०,००० रू लड़की के खाते में दिया जाता है तथा २५,००० रू का घरेलू सामान दिया जाता है','ऐसे परिवार जिनकी वार्षिक आय - ३,००,००० रू से कम हो । लड़की की आयु - १८ वर्ष , लड़के की आयु - २१ वर्ष से कम न हो','परिवार का आय प्रमाण पत्र, आधार कार्ड, बैंक पासबुक की छाया प्रति, लड़के और लड़की का आयु प्रमाण पत्र,','इस योजना के तहत सम्मिलित शादी होने पर ६०,००० रू लड़की के खाते में दिया जाता है तथा २५,००० रू का घरेलू सामान दिया जाता है','समाज कल्याण विभाग'),
('वृद्धजन','निराश्रित महिला पेंशन (विधवा पेंशन) योजना','इस योजना के अंतर्गत १,००० रू प्रति माह के दर से प्रत्येक तिमाही ३,००० रू की धनराशि प्रति लाभार्थी को आधार बेस पेमेंट डी बी टी के माध्यम से विधवा महिला के आधार लिंक बैंक  खाते में प्रेषित की जाती है।','उत्तर प्रदेश का स्थायी निवासी हो, पति की मृत्यु हो चुकी हो, पुनर्विवाह ना किया हो, आयु १८ वर्ष से कम ना हो, और परिवार की आय २,००,००० रू से अधिक ना हो।','फोटो, आधार कार्ड, बैंक पासबुक, आय प्रमाण पत्र, पति का मृत्यु प्रमाण पत्र, मोबाइल नंबर,','१,००० रू प्रति माह के दर से प्रत्येक तिमाही ३,००० रू की धनराशि प्रति लाभार्थी को आधार बेस पेमेंट डी बी टी के माध्यम से वर्ष में चार बार प्रेषित की जाती है।','जिला प्रोबेशन'),
('महिलाएं','कन्या सुमंगला','बालिकाओं को शिक्षा के अवसर प्रदान करने के लिए २५,००० की आर्थिक सहायता ६ चरणों में प्रदान की जाती है।','उत्तर प्रदेश का स्थायी निवासी हो,परिवार की वार्षिक आय अधिकतम ३,००,००० रू हो, अधिकतम २ बच्चियों तक योजना का लाभ दिया जाता है ।','१ चरण - माता पिता का धार कार्ड, बच्चे का बर्थ सर्टिफिकेट, बैंक खाता, मोबाइल नंबर, माता - पिता के साथ बच्ची की फोटो। २ चरण - टीकाकरण कार्ड । ३ चरण - कक्षा एक में दाखिला प्रमाण पत्र । चरण ४ - कक्षा ६ में दाख़िला प्रमाण पत्र। चरण - ५ - कक्षा नौ में दाखिला प्रमाण पत्र । चरण - ६ में स्नातक में दाखिला प्रमाण पत्र।','प्रथम चरण - ५,००० रू, द्वितीय चरण - २,००० , तृतीय चरण - ३,००० रू, चतुर्थ चरण - ३,००० रू, पंचम चरण - ५,००० रू, छठे चरण - ७,००० रू','जिला प्रोबेशन'),
('विधवा / निराश्रित महिलाएं','मुख्यमंत्री बाल सेवा योजना','१ मार्च २०२० के बाद बच्चे के माता या पिता की मृत्यु होने पर बच्चे के शैक्षिक परवरिश से अधिकतम २ बच्चों को २५०० रू प्रति माह दिया जाता है।','ऐसे बच्चे जिनके माता या पिता की मृत्यु १ मार्च २०२० के बाद हुई हो','मृत्यु प्रमाण पत्र, बच्चे के विद्यालय का विवरण, आय प्रमाण पत्र, बच्चे का बैंक खाता, आधार कार्ड (बच्चे एवं अभिभावक का) ।','२५०० रू प्रति माह की दर से त्रैमासिक ७५०० रू वर्ष में ४ बार दिया जाता है','जिला प्रोबेशन'),
('वृद्धजन','दिव्यांग भरण-पोषण अनुदान (दिव्यांग पेंशन)','दिव्यांग व्यक्ति (४०% से कम ना हो) को प्रति माह १,००० रू के दर से पेंशन दी जाती है','१८ साल से आयु अधिक हो, मुख्यचिकित्सा अधिकारी द्वारा जारी स्थाई दिव्यांगता प्रमाण पत्र जिसपर ४०% या उससे अधिक दिव्यांगता अंकित हो','आयु प्रमाण पत्र, आधार कार्ड, बैंक खाता, दिव्यांगता प्रमाण पत्र, ग्राम सभा का प्रस्ताव,','दिव्यांग व्यक्ति को १,००० की दर से त्रैमासिक ३,००० रू वर्ष में ४ बार दिया जाता है । यदि दिव्यांग व्यक्ति कुष्ठ रोग से भी प्रभावित  हो तो उसे ३,००० रू प्रति माह के दर से त्रैमासिक ९,००० रू वर्ष में ४ बार दिया जाता है।','दिव्यांग विभाग'),
('दिव्यांगजन','कृत्रिम अंग/ सहायक  उपकरण','दिव्यांग व्यक्ति/बच्चों को अधिकतम १५,००० रू तक के सहायक उपकरण निःशुल्क दिए जाते हैं','मुख्यचिकित्सा अधिकारी द्वारा जारी स्थाई दिव्यांगता प्रमाण पत्र जिसपर ४०% या उससे अधिक दिव्यांगता अंकित हो','आधार कार्ड, बैंक खाता, दिव्यांगता प्रमाण पत्र, ग्राम सभा का प्रस्ताव','दिव्यांग व्यक्ति/बच्चों को अधिकतम १५,००० रू तक के सहायक उपकरण निःशुल्क दिए जाते हैं','दिव्यांग विभाग'),
('दिव्यांगजन','शादी प्रोत्साहन पुरस्कार योजना','दिव्यांग लड़के से शादी करने पर १५००० रू तथा दिव्यांग लड़की से शादी करने पर २०,००० रू तथा लड़का, लड़की दोनों दिव्यांग हों तो ३५,००० रू  उनके संयुक्त बैंक खाते में दिया जाता है','मुख्यचिकित्सा अधिकारी द्वारा जारी स्थाई दिव्यांगता प्रमाण पत्र जिसपर ४०% या उससे अधिक दिव्यांगता अंकित हो एवं इनकम टैक्स दाता ना हो।','आधार कार्ड, संयुक्त बैंक खाता, दिव्यांगता प्रमाण पत्र, शादी कार्ड, आय प्रमाण पत्र','दिव्यांग लड़के से शादी करने पर १५००० रू तथा दिव्यांग लड़की से शादी करने पर २०,००० रू तथा लड़का, लड़की दोनों दिव्यांग हों तो ३५,००० रू  उनके संयुक्त बैंक खाते में दिया जाता है','दिव्यांग विभाग'),
('प्रवासी / श्रमिक','दुकान निर्माण/संचालन  योजना','ऐसे दिव्यांग व्यक्ति जिनकी गरीबी रेखा के स्तर के दुगने से कम हो तो उसे स्वरोजगार हेतु १०,०००-२०,००० रू तक वित्तीय सहायता दी जाती है','मुख्यचिकित्सा अधिकारी द्वारा जारी स्थाई दिव्यांगता प्रमाण पत्र जिसपर ४०% या उससे अधिक दिव्यांगता अंकित हो','आधार कार्ड, बैंक खाता, दिव्यांगता प्रमाण पत्र, आय प्रमाण पत्र, ज़मीन के दस्तावेज़','ऐसे दिव्यांग व्यक्ति जिनकी गरीबी रेखा के स्तर के दुगने से कम हो तो उसे स्वरोजगार हेतु १०,०००-२०,००० रू तक वित्तीय सहायता दी जाती है','दिव्यांग विभाग'),
('पशुपालक','नंदिनी कृषक समृद्धि योजना','इस योजना में परियोजना लागत ६२.5  लाख जिसमें २५ स्वदेशी गाय पालन का प्रविधान हैं, ५०% पशुपालन द्वारा ३ किश्तों में अनुदान दिया जाता है।','आवेदक स्थानीय निवासी हो एवं 2 एकड़ ज़मीन की उपलब्धता हो','बैंक द्वारा निर्धारित आवेदन पत्र एवं संलग्नक','इस योजना में परियोजना लागत ६२.5  लाख जिसमें २५ स्वदेशी गाय पालन का प्रविधान हैं, ५०% पशुपालन द्वारा ३ किश्तों में अनुदान दिया जाता है।','पशुपालन विभाग'),
